INSERT INTO companies VALUES('b58f75e0-5a7b-4775-8306-42b3c6702e27','Voltage Park','operator','https://voltagepark.com','Cloud AI infrastructure company with $1bn backing and 100+ customers. One of the largest independent GPU cloud operators in the US.','C','AI Cloud','24,000 NVIDIA H100 GPUs (~$1B worth), fully paid, zero debt, zero leasing. Expanded to 35,000+ H100/B200/GB300 post Lightning AI merger (Jan 2026). Six Tier 3 data centers in TX, VA, WA.','No debt or leasing — fully equity-funded via Jed McCaleb / Navigation Fund. Merged with Lightning AI in January 2026.',58,'2026-03-21 02:26:32','2026-03-21 02:49:33',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-03-21 12:37:19',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'uncontacted');
