INSERT INTO email_drafts VALUES('13851bcb-0f6f-49fa-8d01-9fd9813e4f1b','ce1b56b2-d20c-435f-8873-45fe63b331f3','GPU collateral protection for your lending portfolio',unistr('Hi Head,,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs Head at Dell Financial Services, you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'dfs@dell.com');
INSERT INTO email_drafts VALUES('68d81de6-6f39-43e0-a8aa-72479a28719d','9b0b6da8-5667-4af9-80ec-7a85482bd1e6','GPU collateral protection for your lending portfolio',unistr('Hi Rick,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs CEO & Managing Partner at Digital Alpha Advisors, you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'rshrotri@digitalalpha.net');
INSERT INTO email_drafts VALUES('7407e1c9-0a41-4cf9-96f8-c85bfe2cfc05','2accf5aa-f8db-4b18-af13-a28ea13c034e','GPU residual value — new specialty line opportunity',unistr('Hi Jim,\u000a\u000aI wanted to flag an emerging capacity opportunity we think is well-suited for Everest Re Group.\u000a\u000aThe GPU infrastructure market is crossing $100B in financed assets — and the core underwriting challenge is residual value at maturity. Lenders want to deploy into AI infra but need a clear floor on hardware value 3–5 years out. That''s where Corgi comes in.\u000a\u000aThe structure is analogous to automotive residual value programs — an asset class with a proven reinsurance track record — applied to data-center GPUs. The market is early, deal flow is growing, and there''s real capacity need from well-capitalised counterparties.\u000a\u000aOur founders, Isaac and Josh, are building out the reinsurance relationships now. Would it make sense to have a brief introductory call?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Reinsurer/Arranger','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'jwilliamson@everestre.com');
INSERT INTO email_drafts VALUES('dcd73e60-1b07-4f54-8074-0b337f4bf568','bb92d7df-5b91-41f9-af53-3a8081efd416','GPU residual value — new specialty line opportunity',unistr('Hi Richard,\u000a\u000aI wanted to flag an emerging capacity opportunity we think is well-suited for Fidelis Insurance Group.\u000a\u000aThe GPU infrastructure market is crossing $100B in financed assets — and the core underwriting challenge is residual value at maturity. Lenders want to deploy into AI infra but need a clear floor on hardware value 3–5 years out. That''s where Corgi comes in.\u000a\u000aThe structure is analogous to automotive residual value programs — an asset class with a proven reinsurance track record — applied to data-center GPUs. The market is early, deal flow is growing, and there''s real capacity need from well-capitalised counterparties.\u000a\u000aOur founders, Isaac and Josh, are building out the reinsurance relationships now. Would it make sense to have a brief introductory call?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Reinsurer/Arranger','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'rbrindle@fidelisinsurance.com');
INSERT INTO email_drafts VALUES('92f33ae2-9a23-48ed-8a8b-b68023ed6eec','3d465542-d5c8-4623-bab5-1dfb2398816c','Reducing residual value risk on your GPU fleet',unistr('Hi Denvil,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor an operator with a fleet like Fluidstack''s — 10,000+ GPUs — this directly improves your cost of capital and gives lenders the comfort to offer better leverage, longer tenor, or tighter pricing.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'denvil@fluidstack.io');
INSERT INTO email_drafts VALUES('66145471-2e46-4f8d-9c6b-713d95b758d2','3c0022b7-76f9-43df-ad78-970999005bc8','Reducing residual value risk on your GPU fleet',unistr('Hi Anish,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor an operator with a fleet like Foundry''s — 2,000-5,000 GPUs — this directly improves your cost of capital and gives lenders the comfort to offer better leverage, longer tenor, or tighter pricing.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'anish@foundryml.com');
INSERT INTO email_drafts VALUES('df875d72-6af8-41e6-bfb7-3c1cc163de98','13c6f00d-dcef-475f-b18f-a81bf15ec15b','GPU collateral protection for your lending portfolio',unistr('Hi Founder/CEO,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs CEO at GPU Financing (gpufinancing.com), you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'info@gpufinancing.com');
INSERT INTO email_drafts VALUES('00c9c0d6-8f91-4259-97a7-19a20b460aeb','df42cc25-1873-4058-86f9-21c0e5d42485','GPU residual value — new specialty line opportunity',unistr('Hi Tom,\u000a\u000aI wanted to flag an emerging capacity opportunity we think is well-suited for Gallagher Re.\u000a\u000aThe GPU infrastructure market is crossing $100B in financed assets — and the core underwriting challenge is residual value at maturity. Lenders want to deploy into AI infra but need a clear floor on hardware value 3–5 years out. That''s where Corgi comes in.\u000a\u000aThe structure is analogous to automotive residual value programs — an asset class with a proven reinsurance track record — applied to data-center GPUs. The market is early, deal flow is growing, and there''s real capacity need from well-capitalised counterparties.\u000a\u000aOur founders, Isaac and Josh, are building out the reinsurance relationships now. Would it make sense to have a brief introductory call?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Reinsurer/Arranger','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'tom.wakefield@ajg.com');
