INSERT INTO email_drafts VALUES('187cc499-ebe1-4359-9c32-3bd9dde18540','1a271c88-e558-435b-9197-9b0655b27c6b','GPU collateral protection for your lending portfolio',unistr('Hi SLYD,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs Managing Director at SLYD Finance, you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'finance@slyd.com');
INSERT INTO email_drafts VALUES('244d6d26-be78-4685-be64-e93e1d2a9090','6aba1ca9-ae1e-4d4b-863c-09e928fc715f','Reducing residual value risk on your GPU fleet',unistr('Hi CEO/Founder,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor a GPU operator like Silicon Data (SiliconNavigator), this translates directly into a better debt structure: lower spread, longer tenor, or higher leverage — because lenders have a clear floor on collateral value.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'info@silicondata.com');
