INSERT INTO email_drafts VALUES('31a2ebbe-791e-4e68-9da6-9100f7b943bf','354306eb-b886-43fe-8406-22f9245ba9e1','Reducing residual value risk on your GPU fleet',unistr('Hi Darrick,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor an operator with a fleet like TensorWave''s — 8,000 AMD Instinct MI325X GPUs in dedicated training cluster. Liquid-cooled. Building world''s largest liquid-cooled AMD GPU deployment. Run-rate revenue target: $100M+ by end of 2025 (20x YoY). — this directly improves your cost of capital and gives lenders the comfort to offer better leverage, longer tenor, or tighter pricing.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'darrick.horton@tensorwave.com');
