xplain_product"}],"defaultNext":"value_prop"},"value_prop":{"id":"value_prop","type":"speak","text":"We work with structures that give lenders more comfort on residual value at maturity. That can help improve leverage, tenor, or pricing.","pauseAfterMs":500,"defaultNext":"cta"},"cta":{"id":"cta","type":"speak","text":"Would it be useful to show you how this could fit into an existing or upcoming financing package?","pauseAfterMs":200,"defaultNext":"listen_cta"},"listen_cta":{"id":"listen_cta","type":"listen","speechTimeout":8,"branches":[{"condition":"accepts","keywords":["yes","sure","okay","sounds good","works","next week","book","schedule"],"nextNodeId":"book_call"},{"condition":"asks_question","keywords":["what","how","why","explain","tell me","curious"],"nextNodeId":"handle_followup"},{"condition":"declines","keywords":["no","not now","too busy","not interested","pass"],"nextNodeId":"soft_close"}],"defaultNext":"soft_close"},"explain_product":{"id":"explain_product","type":"speak","text":"It is a residual value solution for data-center GPUs. The simple purpose is to reduce lender downside on future hardware value. That can help make debt cheaper or easier to raise. On the next call, Isaac and Josh can walk through how it works in the financing stack.","pauseAfterMs":300,"defaultNext":"cta"},"handle_objection":{"id":"handle_objection","type":"branch","description":"Route to appropriate objection response based on detected intent","branches":[{"condition":"not_interested","nextNodeId":"objection_not_interested"},{"condition":"too_early","nextNodeId":"objection_too_early"},{"condition":"send_info","nextNodeId":"objection_send_info"},{"condition":"who_are_you","nextNodeId":"objection_who_are_you"},{"condition":"already_financed","nextNodeId":"objection_already_financed"},{"condition":"wrong_person","nextNodeId":"objection_wrong_person"}],"defaultNext":"objection_not_interested"},"objection_not_interested":{"id":"objection_not_interested","type":"speak","text":"Unde