PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE companies (
      id                  TEXT PRIMARY KEY,
      name                TEXT NOT NULL,
      type                TEXT NOT NULL CHECK(type IN ('operator', 'lender', 'arranger')),
      website             TEXT,
      description         TEXT,
      priority            TEXT CHECK(priority IN ('A', 'B', 'C')),
      industry_segment    TEXT,
      estimated_gpu_scale TEXT,          -- e.g. "100-500 GPUs", "$50M-$150M"
      financing_status    TEXT,          -- e.g. "active", "upcoming", "unknown"
      qualification_score INTEGER DEFAULT 0,
      created_at          TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
    , founded_year INTEGER, employee_count TEXT, total_raised TEXT, last_funding_round TEXT, investors TEXT, headquarters TEXT, linkedin_url TEXT, twitter_url TEXT, github_url TEXT, recent_news TEXT, hiring_signals TEXT, last_enriched_at DATETIME, sec_ticker TEXT, sec_cik TEXT, gpu_asset_value TEXT, depreciation_schedule TEXT, open_roles_count INTEGER, key_hires TEXT, nvidia_partnership TEXT, outreach_status TEXT DEFAULT 'uncontacted');
CREATE TABLE contacts (
      id           TEXT PRIMARY KEY,
      company_id   TEXT NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
      name         TEXT NOT NULL,
      title        TEXT,
      email        TEXT,
      phone        TEXT,
      linkedin_url TEXT,
      source       TEXT,                 -- e.g. "website", "linkedin", "manual"
      verified     INTEGER NOT NULL DEFAULT 0,  -- 0 = unverified, 1 = verified
      created_at   TEXT NOT NULL DEFAULT (datetime('now'))
    , twitter_url TEXT, github_url TEXT, bio TEXT, tenure TEXT, email_pattern TEXT, email_confidence REAL DEFAULT 0, last_enriched_at DATETIME);
CREATE TABLE outreach_log (
      id             TEXT PRIMARY KEY,
      contact_id     TEXT NOT NULL REFERENCES contacts(id) ON DELETE CASCADE,
      channel        TEXT NOT NULL CHECK(channel IN ('call', 'email')),
      status         TEXT NOT NULL CHECK(status IN ('draft', 'scheduled', 'completed', 'failed')),
      script_version TEXT,              -- A/B/C/D/E
      notes          TEXT,
      scheduled_at   TEXT,
      completed_at   TEXT,
      created_at     TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE TABLE email_drafts (
      id            TEXT PRIMARY KEY,
      contact_id    TEXT NOT NULL REFERENCES contacts(id) ON DELETE CASCADE,
      subject       TEXT NOT NULL,
      body          TEXT NOT NULL,
      template_name TEXT,
      status        TEXT NOT NULL CHECK(status IN ('draft', 'approved', 'sent')) DEFAULT 'draft',
      created_at    TEXT NOT NULL DEFAULT (datetime('now'))
    , campaign_id TEXT, ab_variant TEXT DEFAULT 'a', sequence_day INTEGER DEFAULT 0, scheduled_at TEXT, sent_at TEXT, opened_at TEXT, clicked_at TEXT, from_email TEXT, to_email TEXT);
CREATE TABLE call_scripts (
      id                TEXT PRIMARY KEY,
      company_id        TEXT NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
      script_version    TEXT NOT NULL CHECK(script_version IN ('A', 'B', 'C', 'D', 'E')),
      customized_script TEXT NOT NULL,  -- JSON: { lines: [...], followups: [...] }
      buyer_type        TEXT NOT NULL,  -- operator / lender / arranger
      created_at        TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE TABLE research_notes (
      id         TEXT PRIMARY KEY,
      company_id TEXT NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
      source_url TEXT,
      summary    TEXT,
      raw_data   TEXT,                  -- JSON blob
      created_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE TABLE call_plans (
      id              TEXT PRIMARY KEY,
      company_id      TEXT NOT NULL,
      contact_id      TEXT,
      script_version  TEXT NOT NULL,
      call_plan_json  TEXT NOT NULL,
      audio_files     TEXT,           -- JSON array of generated audio paths
      status          TEXT NOT NULL DEFAULT 'draft'
                        CHECK(status IN ('draft', 'dry_run', 'queued', 'in_progress', 'completed', 'failed')),
      dry_run         INTEGER NOT NULL DEFAULT 1,
      twilio_call_sid TEXT,
      call_recording_url TEXT,
      notes           TEXT,
      created_at      TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE TABLE email_campaigns (
      id              TEXT PRIMARY KEY,
      name            TEXT NOT NULL,
      description     TEXT,
      status          TEXT NOT NULL DEFAULT 'draft'
                      CHECK(status IN ('draft', 'approved', 'scheduled', 'sending', 'sent', 'paused')),
      audience_type   TEXT CHECK(audience_type IN ('operator', 'lender', 'arranger', 'all')),
      priority_filter TEXT,         -- 'A', 'B', 'C', or NULL for all
      ab_variant      TEXT DEFAULT 'a' CHECK(ab_variant IN ('a', 'b')),
      ab_test_enabled INTEGER DEFAULT 0,   -- 1 = split 50/50 a/b
      total_contacts  INTEGER DEFAULT 0,
      total_drafted   INTEGER DEFAULT 0,
      total_sent      INTEGER DEFAULT 0,
      total_opened    INTEGER DEFAULT 0,
      total_clicked   INTEGER DEFAULT 0,
      total_replied   INTEGER DEFAULT 0,
      approved_by     TEXT,
      approved_at     TEXT,
      created_at      TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE TABLE campaign_contacts (
      campaign_id TEXT NOT NULL REFERENCES email_campaigns(id) ON DELETE CASCADE,
      contact_id  TEXT NOT NULL REFERENCES contacts(id)         ON DELETE CASCADE,
      status      TEXT NOT NULL DEFAULT 'pending'
                  CHECK(status IN ('pending', 'drafted', 'sent', 'replied', 'unsubscribed')),
      added_at    TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (campaign_id, contact_id)
    );
CREATE TABLE enrichment_log (
      id          TEXT PRIMARY KEY,
      entity_type TEXT NOT NULL,
      entity_id   TEXT NOT NULL,
      source      TEXT NOT NULL,
      data_found  TEXT,
      created_at  DATETIME DEFAULT (datetime('now'))
    );
CREATE TABLE call_results (
    id               TEXT PRIMARY KEY,
    company_id       TEXT NOT NULL,
    contact_id       TEXT,
    call_provider    TEXT DEFAULT 'vapi',
    call_provider_id TEXT,
    status           TEXT NOT NULL DEFAULT 'initiated'
      CHECK(status IN ('initiated','ringing','in_progress','voicemail','completed','failed','no_answer')),
    outcome          TEXT
      CHECK(outcome IN ('meeting_booked','interested','not_interested','callback_requested','wrong_person','voicemail_left','no_answer','failed')),
    duration_seconds INTEGER,
    recording_url    TEXT,
    transcript       TEXT,
    summary          TEXT,
    notes            TEXT,
    call_cost        REAL,
    created_at       TEXT NOT NULL,
    updated_at       TEXT
  );
CREATE TABLE call_retries (
    id             TEXT PRIMARY KEY,
    company_id     TEXT NOT NULL,
    contact_id     TEXT NOT NULL,
    attempt_number INTEGER NOT NULL DEFAULT 1,
    max_attempts   INTEGER NOT NULL DEFAULT 3,
    scheduled_for  TEXT NOT NULL,
    status         TEXT DEFAULT 'scheduled'
      CHECK(status IN ('scheduled','completed','cancelled','expired')),
    call_result_id TEXT,
    created_at     TEXT NOT NULL
  );
CREATE TABLE post_call_emails (
    id              TEXT PRIMARY KEY,
    call_result_id  TEXT NOT NULL,
    contact_id      TEXT,
    template_used   TEXT,
    subject         TEXT,
    status          TEXT DEFAULT 'pending'
      CHECK(status IN ('pending','sent','failed','skipped')),
    scheduled_for   TEXT,
    sent_at         TEXT,
    created_at      TEXT NOT NULL
  );
CREATE TABLE email_templates (
    id                 TEXT PRIMARY KEY,
    name               TEXT NOT NULL UNIQUE,
    buyer_type         TEXT NOT NULL,          -- operator | lender | arranger | all
    subject            TEXT NOT NULL,
    body               TEXT NOT NULL,          -- Handlebars template with {{merge_fields}}
    sequence_position  INTEGER NOT NULL DEFAULT 1,   -- 1=cold intro, 2=followup1, 3=followup2, 4=breakup
    days_after_previous INTEGER NOT NULL DEFAULT 0,  -- days after previous sequence email
    created_at         TEXT NOT NULL DEFAULT (datetime('now'))
  );
CREATE TABLE portal_views (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      company_id TEXT NOT NULL,
      company_slug TEXT NOT NULL,
      viewed_at TEXT NOT NULL DEFAULT (datetime('now')),
      ip_address TEXT,
      user_agent TEXT
    );
CREATE TABLE portal_configs (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      company_id TEXT NOT NULL UNIQUE,
      company_slug TEXT NOT NULL UNIQUE,
      custom_message TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
CREATE INDEX idx_contacts_company    ON contacts(company_id);
CREATE INDEX idx_outreach_contact    ON outreach_log(contact_id);
CREATE INDEX idx_email_drafts_contact ON email_drafts(contact_id);
CREATE INDEX idx_call_scripts_company ON call_scripts(company_id);
CREATE INDEX idx_research_company    ON research_notes(company_id);
CREATE INDEX idx_companies_priority  ON companies(priority);
CREATE INDEX idx_companies_type      ON companies(type);
CREATE INDEX idx_call_plans_company ON call_plans(company_id);
CREATE INDEX idx_call_plans_status  ON call_plans(status);
CREATE INDEX idx_campaign_contacts_campaign ON campaign_contacts(campaign_id);
CREATE INDEX idx_email_campaigns_status ON email_campaigns(status);
CREATE INDEX idx_email_drafts_campaign ON email_drafts(campaign_id);
CREATE INDEX idx_email_drafts_status   ON email_drafts(status);
CREATE INDEX idx_email_drafts_sched    ON email_drafts(scheduled_at);
CREATE INDEX idx_enrichment_log_entity
      ON enrichment_log(entity_type, entity_id);
CREATE INDEX idx_enrichment_log_source
      ON enrichment_log(source);
CREATE INDEX idx_enrichment_log_created
      ON enrichment_log(created_at);
CREATE INDEX idx_call_results_company  ON call_results(company_id);
CREATE INDEX idx_call_results_status   ON call_results(status);
CREATE INDEX idx_call_results_outcome  ON call_results(outcome);
CREATE INDEX idx_call_results_created  ON call_results(created_at);
CREATE INDEX idx_call_retries_contact   ON call_retries(contact_id);
CREATE INDEX idx_call_retries_status    ON call_retries(status);
CREATE INDEX idx_call_retries_scheduled ON call_retries(scheduled_for);
CREATE INDEX idx_post_call_emails_call_result ON post_call_emails(call_result_id);
CREATE INDEX idx_post_call_emails_contact     ON post_call_emails(contact_id);
CREATE INDEX idx_post_call_emails_status      ON post_call_emails(status);
CREATE INDEX idx_portal_views_company ON portal_views(company_id);
CREATE INDEX idx_portal_views_slug ON portal_views(company_slug);
COMMIT;
